class ErrorContext:
    """Builds detailed error context for gRPC responses."""

    @staticmethod
    def build_error_details(
        method_name,
        exception,
        service_state,
        request_data=None,
        additional_context=None
    ):
        """Build comprehensive error details for debugging."""
        exc_type, exc_value, exc_tb = sys.exc_info()

        error_details = {
            "error_type": type(exception).__name__,
            "error_message": str(exception),
            "method": method_name,
            "timestamp": datetime.utcnow().isoformat(),
            "stack_trace": traceback.format_exception(exc_type, exc_value, exc_tb),
            "stack_frames": [],
            "service_state_snapshot": {
                "active_requests": service_state.active_requests,
                "total_requests": service_state.request_count,
                "total_errors": service_state.error_count,
                "dependencies": service_state.dependencies,
            },
        }

        # Extract detailed frame information
        if exc_tb:
            for frame_info in traceback.extract_tb(exc_tb):
                error_details["stack_frames"].append({
                    "filename": frame_info.filename,
                    "line_number": frame_info.lineno,
                    "function": frame_info.name,
                    "code": frame_info.line,
                })

            # Get local variables from the innermost frame
            tb = exc_tb
            while tb.tb_next:
                tb = tb.tb_next
            local_vars = {}
            for key, value in tb.tb_frame.f_locals.items():
                try:
                    # Avoid serializing complex objects
                    if isinstance(value, (str, int, float, bool, list, dict, type(None))):
                        local_vars[key] = repr(value)
                    else:
                        local_vars[key] = f"<{type(value).__name__}>"
                except Exception:
                    local_vars[key] = "<unserializable>"
            error_details["local_variables"] = local_vars

        if request_data:
            error_details["request_data"] = request_data

        if additional_context:
            error_details["additional_context"] = additional_context

        # Add Python/system info
        error_details["system_info"] = {
            "python_version": sys.version,
            "pid": os.getpid(),
            "thread": threading.current_thread().name,
        }

        return error_details


