def _extract_request_data(request):
    """Extract serializable data from a protobuf request."""
    try:
        data = {}
        for field in request.DESCRIPTOR.fields:
            value = getattr(request, field.name)
            data[field.name] = str(value) if not isinstance(value, (str, int, float, bool)) else value
        return data
    except Exception:
        return {"raw": str(request)}


